import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter, resetEmailMessageIdCounter } from '../../src/adapters/email.adapter.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let logRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);
    resetNotificationLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a sent notification', () => {
      const notification: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date('2026-01-15T10:00:00Z'),
        updatedAt: new Date('2026-01-15T10:00:01Z'),
        messageId: 'email-0001',
      };

      const entry = historyService.logNotification(notification);

      expect(entry).toBeDefined();
      expect(entry!.id).toBe('nlog-0001');
      expect(entry!.notificationId).toBe('notif-0001');
      expect(entry!.recipient).toBe('alice@example.com');
      expect(entry!.channel).toBe('email');
      expect(entry!.subject).toBe('Order Confirmation: order-1');
      expect(entry!.status).toBe('sent');
      expect(entry!.priority).toBe('normal');
      expect(entry!.messageId).toBe('email-0001');
      expect(entry!.error).toBeUndefined();
    });

    it('should log a failed notification', () => {
      const notification: Notification = {
        id: 'notif-0002',
        type: 'email',
        recipient: 'bob@example.com',
        subject: 'Order Update',
        body: 'Your order status changed.',
        status: 'failed',
        priority: 'normal',
        createdAt: new Date('2026-01-15T10:00:00Z'),
        updatedAt: new Date('2026-01-15T10:00:01Z'),
        error: 'SMTP connection refused',
      };

      const entry = historyService.logNotification(notification);

      expect(entry).toBeDefined();
      expect(entry!.status).toBe('failed');
      expect(entry!.error).toBe('SMTP connection refused');
      expect(entry!.messageId).toBeUndefined();
    });

    it('should log with optional metadata', () => {
      const notification: Notification = {
        id: 'notif-0003',
        type: 'webhook',
        recipient: 'https://hooks.example.com/notify',
        subject: 'Order Created',
        body: 'New order placed.',
        status: 'sent',
        priority: 'high',
        createdAt: new Date('2026-01-15T10:00:00Z'),
        updatedAt: new Date('2026-01-15T10:00:01Z'),
      };

      const metadata = { orderId: 'order-1', template: 'order-confirmation' };
      const entry = historyService.logNotification(notification, metadata);

      expect(entry).toBeDefined();
      expect(entry!.metadata).toEqual({ orderId: 'order-1', template: 'order-confirmation' });
    });

    it('should generate sequential log IDs', () => {
      const makeNotification = (id: string): Notification => ({
        id,
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      });

      const entry1 = historyService.logNotification(makeNotification('notif-0001'));
      const entry2 = historyService.logNotification(makeNotification('notif-0002'));
      const entry3 = historyService.logNotification(makeNotification('notif-0003'));

      expect(entry1!.id).toBe('nlog-0001');
      expect(entry2!.id).toBe('nlog-0002');
      expect(entry3!.id).toBe('nlog-0003');
    });

    it('should not throw on duplicate notification IDs (different log entries)', () => {
      const notification: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      // Log the same notification twice — generates different log entry IDs
      const entry1 = historyService.logNotification(notification);
      const entry2 = historyService.logNotification(notification);

      expect(entry1!.id).toBe('nlog-0001');
      expect(entry2!.id).toBe('nlog-0002');
      expect(entry1!.notificationId).toBe('notif-0001');
      expect(entry2!.notificationId).toBe('notif-0001');
    });
  });

  describe('getLogEntry', () => {
    it('should return a log entry by ID', () => {
      const notification: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      historyService.logNotification(notification);

      const entry = historyService.getLogEntry('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry!.notificationId).toBe('notif-0001');
    });

    it('should return undefined for non-existent ID', () => {
      expect(historyService.getLogEntry('nlog-9999')).toBeUndefined();
    });
  });

  describe('getHistoryByRecipient', () => {
    it('should return entries for a specific recipient', () => {
      const aliceNotif: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test 1',
        body: 'Body 1',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      const bobNotif: Notification = {
        id: 'notif-0002',
        type: 'email',
        recipient: 'bob@example.com',
        subject: 'Test 2',
        body: 'Body 2',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      historyService.logNotification(aliceNotif);
      historyService.logNotification(bobNotif);
      historyService.logNotification({
        ...aliceNotif,
        id: 'notif-0003',
        subject: 'Test 3',
      });

      const aliceEntries = historyService.getHistoryByRecipient('alice@example.com');
      const bobEntries = historyService.getHistoryByRecipient('bob@example.com');

      expect(aliceEntries).toHaveLength(2);
      expect(bobEntries).toHaveLength(1);
    });

    it('should return empty array for unknown recipient', () => {
      expect(historyService.getHistoryByRecipient('unknown@example.com')).toHaveLength(0);
    });
  });

  describe('getHistoryByChannel', () => {
    it('should return entries for a specific channel', () => {
      const emailNotif: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Email notification',
        body: 'Body',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      const webhookNotif: Notification = {
        id: 'notif-0002',
        type: 'webhook',
        recipient: 'https://hooks.example.com',
        subject: 'Webhook notification',
        body: 'Body',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      historyService.logNotification(emailNotif);
      historyService.logNotification(webhookNotif);

      const emailEntries = historyService.getHistoryByChannel('email');
      const webhookEntries = historyService.getHistoryByChannel('webhook');
      const smsEntries = historyService.getHistoryByChannel('sms');

      expect(emailEntries).toHaveLength(1);
      expect(webhookEntries).toHaveLength(1);
      expect(smsEntries).toHaveLength(0);
    });
  });

  describe('getHistoryByStatus', () => {
    it('should return entries with a specific status', () => {
      const sentNotif: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Sent',
        body: 'Body',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      const failedNotif: Notification = {
        id: 'notif-0002',
        type: 'email',
        recipient: 'bob@example.com',
        subject: 'Failed',
        body: 'Body',
        status: 'failed',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
        error: 'SMTP error',
      };

      historyService.logNotification(sentNotif);
      historyService.logNotification(failedNotif);

      const sentEntries = historyService.getHistoryByStatus('sent');
      const failedEntries = historyService.getHistoryByStatus('failed');

      expect(sentEntries).toHaveLength(1);
      expect(sentEntries[0]!.notificationId).toBe('notif-0001');
      expect(failedEntries).toHaveLength(1);
      expect(failedEntries[0]!.notificationId).toBe('notif-0002');
    });
  });

  describe('getHistoryByDateRange', () => {
    it('should return entries within a date range', () => {
      const jan15 = new Date('2026-01-15T10:00:00Z');
      const jan20 = new Date('2026-01-20T10:00:00Z');
      const feb01 = new Date('2026-02-01T10:00:00Z');

      const makeNotif = (id: string, date: Date): Notification => ({
        id,
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        status: 'sent',
        priority: 'normal',
        createdAt: date,
        updatedAt: date,
      });

      historyService.logNotification(makeNotif('notif-0001', jan15));
