          updatedAt: new Date(`2026-01-${String(i).padStart(2, '0')}T10:00:00Z`),
        };
        historyService.logNotification(notification);
      }
    });

    it('should return first page', () => {
      const result = historyService.queryHistoryPaginated({}, 1, 5);

      expect(result.items).toHaveLength(5);
      expect(result.page).toBe(1);
      expect(result.pageSize).toBe(5);
      expect(result.totalItems).toBe(15);
      expect(result.totalPages).toBe(3);
      expect(result.hasNext).toBe(true);
      expect(result.hasPrevious).toBe(false);
    });

    it('should return second page', () => {
      const result = historyService.queryHistoryPaginated({}, 2, 5);

      expect(result.items).toHaveLength(5);
      expect(result.page).toBe(2);
      expect(result.hasNext).toBe(true);
      expect(result.hasPrevious).toBe(true);
    });

    it('should return last page', () => {
      const result = historyService.queryHistoryPaginated({}, 3, 5);

      expect(result.items).toHaveLength(5);
      expect(result.page).toBe(3);
      expect(result.hasNext).toBe(false);
      expect(result.hasPrevious).toBe(true);
    });

    it('should paginate filtered results', () => {
      // Add some entries with a different recipient
      const bobNotif: Notification = {
        id: 'notif-0099',
        type: 'email',
        recipient: 'bob@example.com',
        subject: 'Bob notification',
        body: 'Body',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      historyService.logNotification(bobNotif);

      const result = historyService.queryHistoryPaginated(
        { recipient: 'alice@example.com' },
        1,
        10,
      );

      expect(result.totalItems).toBe(15);
      expect(result.items).toHaveLength(10);
      expect(result.totalPages).toBe(2);
    });

    it('should throw for invalid page number', () => {
      expect(() => historyService.queryHistoryPaginated({}, 0, 5)).toThrow();
    });

    it('should throw for invalid page size', () => {
      expect(() => historyService.queryHistoryPaginated({}, 1, 0)).toThrow();
    });
  });

  describe('getTotalCount', () => {
    it('should return 0 when no entries exist', () => {
      expect(historyService.getTotalCount()).toBe(0);
    });

    it('should return correct count after logging', () => {
      const notification: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      historyService.logNotification(notification);
      historyService.logNotification({ ...notification, id: 'notif-0002' });

      expect(historyService.getTotalCount()).toBe(2);
    });
  });

  describe('getAllHistory', () => {
    it('should return all log entries', () => {
      const notification: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      historyService.logNotification(notification);
      historyService.logNotification({ ...notification, id: 'notif-0002' });
      historyService.logNotification({ ...notification, id: 'notif-0003' });

      expect(historyService.getAllHistory()).toHaveLength(3);
    });
  });

  describe('clearHistory', () => {
    it('should clear all log entries', () => {
      const notification: Notification = {
        id: 'notif-0001',
        type: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        status: 'sent',
        priority: 'normal',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      historyService.logNotification(notification);
      historyService.logNotification({ ...notification, id: 'notif-0002' });

      expect(historyService.getTotalCount()).toBe(2);

      historyService.clearHistory();

      expect(historyService.getTotalCount()).toBe(0);
      expect(historyService.getAllHistory()).toHaveLength(0);
    });
  });
});

describe('NotificationService with history integration', () => {
  let db: Database;
  let logRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;
  let eventBus: EventBus;
  let notifService: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);
    eventBus = new EventBus();
    notifService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notifService.registerAdapter(emailAdapter);
    notifService.setHistoryService(historyService);
    resetNotificationLogIdCounter();
    resetNotificationIdCounter();
    resetEmailMessageIdCounter();
  });

  it('should log notification to history when order:created event fires', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // Verify notification was sent
    expect(notifService.getNotificationCount()).toBe(1);

    // Verify history was logged
    const history = historyService.getAllHistory();
    expect(history).toHaveLength(1);
    expect(history[0]!.recipient).toBe('alice@example.com');
    expect(history[0]!.channel).toBe('email');
    expect(history[0]!.status).toBe('sent');
    expect(history[0]!.subject).toContain('Order Confirmation');
    expect(history[0]!.notificationId).toBe('notif-0001');
    expect(history[0]!.messageId).toBe('email-0001');
  });

  it('should log notification to history when order:status-changed event fires', async () => {
    const event: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const history = historyService.getAllHistory();
    expect(history).toHaveLength(1);
    expect(history[0]!.channel).toBe('email');
    expect(history[0]!.status).toBe('sent');
    expect(history[0]!.subject).toContain('Order Update');
  });

  it('should log failed notifications to history', async () => {
    // Replace adapter with a failing one
    notifService.unregisterAdapter('email');
    const failingAdapter = {
      type: 'email' as const,
      async send() {
        return {
          success: false,
          error: 'SMTP connection refused',
          timestamp: new Date(),
        };
      },
    };
    notifService.registerAdapter(failingAdapter);

    const notification = await notifService.dispatchNotification({
      type: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
    });

    expect(notification.status).toBe('failed');

    const history = historyService.getAllHistory();
    expect(history).toHaveLength(1);
    expect(history[0]!.status).toBe('failed');
    expect(history[0]!.error).toBe('SMTP connection refused');
  });

  it('should log notifications even without an adapter (backward compatible)', async () => {
    notifService.unregisterAdapter('email');

    await notifService.dispatchNotification({
      type: 'email',
      recipient: 'alice@example.com',
      subject: 'No Adapter Test',
      body: 'Test body',
    });

    const history = historyService.getAllHistory();
    expect(history).toHaveLength(1);
    expect(history[0]!.status).toBe('sent');
    expect(history[0]!.subject).toBe('No Adapter Test');
  });

  it('should log multiple notifications from different events', async () => {
    const orderCreatedEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    const statusChangedEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    await eventBus.emit(orderCreatedEvent);
    await eventBus.emit(statusChangedEvent);

    const history = historyService.getAllHistory();
    expect(history).toHaveLength(2);
    expect(history[0]!.subject).toContain('Order Confirmation');
    expect(history[1]!.subject).toContain('Order Update');
  });

  it('should allow querying history by recipient after events', async () => {
    const makeOrderCreated = (userId: string, email: string): OrderCreatedEvent => ({
      type: 'order:created',
      order: {
        id: `order-${userId}`,
        userId,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: userId,
        name: userId,
        email,
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    });

    await eventBus.emit(makeOrderCreated('user-1', 'alice@example.com'));
    await eventBus.emit(makeOrderCreated('user-2', 'bob@example.com'));

    const aliceHistory = historyService.getHistoryByRecipient('alice@example.com');
    const bobHistory = historyService.getHistoryByRecipient('bob@example.com');

    expect(aliceHistory).toHaveLength(1);
    expect(bobHistory).toHaveLength(1);
  });

  it('should work without history service set (backward compatible)', async () => {
    notifService.setHistoryService(null);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // Notification should still be dispatched normally
    expect(notifService.getNotificationCount()).toBe(1);

    // History should be empty since service is not set
    expect(historyService.getAllHistory()).toHaveLength(0);
  });

  it('should capture priority in history', async () => {
    await notifService.dispatchNotification({
      type: 'email',
      recipient: 'alice@example.com',
      subject: 'Urgent',
      body: 'Urgent message',
      priority: 'urgent',
    });

    const history = historyService.getAllHistory();
    expect(history).toHaveLength(1);
    expect(history[0]!.priority).toBe('urgent');
  });
});

