+/**
+ * Repository for NotificationLogEntry data access.
+ *
+ * Extends BaseRepository with notification-log-specific query methods.
+ * Stores notification history entries in the 'notification-logs' collection.
+ *
+ * Provides queries by recipient, channel, status, and date range.
+ *
+ * Depends on the Database utility layer for storage.
+ */
+
+import type { DatabaseRecord } from '../utils/database.js';
+import type { Database } from '../utils/database.js';
+import type {
+  NotificationLogEntry,
+  NotificationLogQuery,
+} from '../models/notification-log.js';
+import type {
+  NotificationType,
+  NotificationStatus,
+  NotificationPriority,
+} from '../models/notification.js';
+import { BaseRepository } from './base.repository.js';
+
+export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
+  constructor(db: Database) {
+    super(db, 'notification-logs');
+  }
+
+  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
+    const entry: NotificationLogEntry = {
+      id: record['id'] as string,
+      notificationId: record['notificationId'] as string,
+      recipient: record['recipient'] as string,
+      channel: record['channel'] as NotificationType,
+      subject: record['subject'] as string,
+      status: record['status'] as NotificationStatus,
+      priority: record['priority'] as NotificationPriority,
+      sentAt: new Date(record['sentAt'] as string),
+    };
+
+    if (record['messageId'] !== undefined) {
+      entry.messageId = record['messageId'] as string;
+    }
+
+    if (record['error'] !== undefined) {
+      entry.error = record['error'] as string;
+    }
+
+    if (record['metadata'] !== undefined) {
+      entry.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
+    }
+
+    return entry;
+  }
+
+  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
+    const record: DatabaseRecord = {
+      id: entity.id,
+      notificationId: entity.notificationId,
+      recipient: entity.recipient,
+      channel: entity.channel,
+      subject: entity.subject,
+      status: entity.status,
+      priority: entity.priority,
+      sentAt: entity.sentAt.toISOString(),
+    };
+
+    if (entity.messageId !== undefined) {
+      record['messageId'] = entity.messageId;
+    }
+
+    if (entity.error !== undefined) {
+      record['error'] = entity.error;
+    }
+
+    if (entity.metadata !== undefined) {
+      record['metadata'] = JSON.stringify(entity.metadata);
+    }
+
+    return record;
+  }
+
+  /**
+   * Find all log entries for a specific recipient.
+   */
+  findByRecipient(recipient: string): NotificationLogEntry[] {
+    return this.findAll((entry) => entry.recipient === recipient);
+  }
+
+  /**
+   * Find all log entries for a specific delivery channel.
+   */
+  findByChannel(channel: NotificationType): NotificationLogEntry[] {
+    return this.findAll((entry) => entry.channel === channel);
+  }
+
+  /**
+   * Find all log entries with a specific delivery status.
+   */
+  findByStatus(status: NotificationStatus): NotificationLogEntry[] {
+    return this.findAll((entry) => entry.status === status);
+  }
+
+  /**
+   * Find all log entries within a date range (inclusive).
+   */
+  findByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
+    return this.findAll(
+      (entry) => entry.sentAt >= startDate && entry.sentAt <= endDate,
+    );
+  }
+
+  /**
+   * Query log entries with a composite filter.
+   *
+   * All specified filter fields are combined with AND logic.
+   * Unspecified fields are ignored (match everything).
+   */
+  query(filter: NotificationLogQuery): NotificationLogEntry[] {
+    return this.findAll((entry) => {
+      if (filter.recipient !== undefined && entry.recipient !== filter.recipient) {
+        return false;
+      }
+      if (filter.channel !== undefined && entry.channel !== filter.channel) {
+        return false;
+      }
+      if (filter.status !== undefined && entry.status !== filter.status) {
+        return false;
+      }
+      if (filter.startDate !== undefined && entry.sentAt < filter.startDate) {
+        return false;
+      }
+      if (filter.endDate !== undefined && entry.sentAt > filter.endDate) {
+        return false;
+      }
+      return true;
+    });
+  }
+}

